VALUES
  ('judicial-d35ec6db-moex-00177', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲聽到隔壁鄰居乙的消防警報器大響，久久不停，甲以為乙家失火，趕緊踹門衝入屋內打算救火， 孰知原來是警報器故障了，事實上並無火災。此等情形係屬於刑法學理上之何種錯誤？', '["構成要件錯誤", "禁止錯誤", "容許構成要件錯誤", "容許錯誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00178', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '裁判確定前犯數罪者，應併合處罰之，下列何者不合乎刑法第51條併合處罰規定？', '["宣告死刑與有期徒刑10年，分別執行之", "宣告2個死刑，執行1個死刑", "宣告褫奪公權5年與1年，執行5年", "宣告有期徒刑3年與罰金3萬元，併執行之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00179', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '關於緩刑及假釋制度的比較，下列敘述何者錯誤？', '["緩刑制度是用以救濟短期自由刑的弊端；假釋制度是用以救濟長期自由刑的弊端", "緩刑是由法院裁判；假釋是由典獄長報請法務部核定", "緩刑期間是2年以上5年以下；假釋期間，是有期徒刑所餘的刑期再加上5年的觀察期", "緩刑期滿，而緩刑之宣告未經撤銷者，其刑之宣告失其效力；有期徒刑所餘刑期內未經撤銷假 釋者，其未執行之刑，以已執行論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00180', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '關於外國人犯罪之驅逐出境，下列敘述何者正確？', '["外國人甲受無期徒刑之宣告，應於執行完畢後驅逐出境", "外國人乙受10年有期徒刑之宣告，應於執行完畢後驅逐出境", "外國人丙受2年有期徒刑之宣告，得於執行完畢後驅逐出境", "外國人丁受30日拘役之宣告，得於執行完畢後驅逐出境"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00181', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '公務員甲基於圖利犯意，明知違法而讓公共工程承包商遲延給付，且未沒收保證金，因被媒體揭 露後，甲才去函督促承包商履約。甲之刑責為何？', '["成立公務員不違背職務受賄罪", "成立違法圖利罪之中止未遂", "甲成立違法圖利罪之既遂犯", "甲不成立犯罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00182', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲為某市環保局正式公務員，平日認真取締不法業者，某週末假日，巧遇其業務上曾取締的業者 乙，乙記得甲是當時取締他的公務員，乙竟憤而打傷甲，乙成立何罪？', '["妨害公務罪", "普通傷害罪", "甲若出示公務員證件，乙即成立妨害公務罪", "甲若因而受傷，乙即成立妨害公務罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00183', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '解送依法拘禁之人犯甲時，負責看管人犯之員警乙，不小心讓甲脫逃。甲、乙之行為，下列敘述 何者正確？', '["甲、乙均不成立犯罪", "甲成立脫逃罪；乙不成立犯罪", "甲不成立犯罪；乙成立過失致脫逃罪", "甲成立脫逃罪；乙成立過失致脫逃罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00184', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '甲到警察局報案，表示其剛才所領的薪水被飛車搶奪，警察調閱街頭錄影帶發現並無此事，甲才 承認因為賭博將錢花光，對太太無法交代，才出此下策，警察應如何處理甲之行為？', '["應偵辦甲刑法第169條的誣告他人罪", "不應偵辦甲行為，因為其未誣告他人", "應偵辦甲刑法第171條未指定犯人誣告罪", "不應偵辦甲行為，因其行為情有可原"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00185', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關刑法第185條之4肇事逃逸罪，下列敘述何者正確？', '["甲駕駛汽車失控，撞擊路邊停放之乙車，導致乙車車門凹陷，甲立即逃逸，甲成立本罪", "甲與乙均騎自行車，在車道上相撞，乙受傷而甲逃逸，甲成立本罪", "甲駕駛汽車失控，撞擊乙車，導致乙受輕傷，甲立即逃逸，甲不成立本罪", "甲駕駛汽車失控而撞上前方之機車，機車騎士乙當場死亡，甲立即逃逸，甲成立本罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00186', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-112-e2754278', 'sub-judicial-d35ec6db-01', NULL, 'single_choice', '有關刑法第15章偽造文書印文罪，下列敘述何者錯誤？', '["偽造私文書或偽造公文書罪都必須足生損害於他人或公眾", "變造汽車牌照號碼是成立刑法第212條變造特種文書罪", "偽造臺灣臺北地方法院的印文成立刑法第217條僞造公印文罪", "互助會標單不是刑法第220條所稱之準文書"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:12+00:00", "source_pdf_sha1": "d730c10a9f02", "answer_pdf_sha1": "011096dce3ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "201", "s": "0504", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
